const setup = $('⚙️ Setup').first().json;
const ads = $json.data || [];
const roasZiel = parseFloat(setup.ROAS_ZIEL);
const minSpend = parseFloat(setup.MIN_SPEND_FUER_BEWERTUNG);

function kaeufe(a) {
  const x = (a.actions || []).find(v => v.action_type === 'purchase' || v.action_type === 'omni_purchase' || v.action_type === 'offsite_conversion.fb_pixel_purchase');
  return x ? parseFloat(x.value) : 0;
}
function umsatz(a) {
  const x = (a.action_values || []).find(v => v.action_type === 'purchase' || v.action_type === 'omni_purchase' || v.action_type === 'offsite_conversion.fb_pixel_purchase');
  return x ? parseFloat(x.value) : 0;
}

const bewertet = [];
const killListe = [];
for (const a of ads) {
  const spend = parseFloat(a.spend || 0);
  const rev = umsatz(a);
  const k = kaeufe(a);
  const roas = spend > 0 ? rev / spend : 0;
  let status = '👀 BEOBACHTEN';
  if (spend >= minSpend && roas >= roasZiel) status = '🚀 SKALIEREN';
  if (spend >= minSpend && roas < 1) {
    status = '💀 KILLEN';
    killListe.push({ ad_id: a.ad_id, ad_name: a.ad_name, spend: spend.toFixed(2), roas: roas.toFixed(2) });
  }
  bewertet.push('- [' + status + '] "' + a.ad_name + '" (Kampagne: ' + a.campaign_name + ') | Spend: ' + spend.toFixed(2) + ' | Kaeufe: ' + k + ' | Umsatz: ' + rev.toFixed(2) + ' | ROAS: ' + roas.toFixed(2) + ' | CTR: ' + (a.ctr || '0') + '% | CPC: ' + (a.cpc || '0'));
}

if (bewertet.length === 0) {
  return [{ json: { prompt: '', keine_ads: true, kill_liste: [], telegram_text: '🎛️ ADS-MANAGER · ' + setup.SHOP_NAME + '\n\nGestern liefen keine Ads (oder noch keine Daten). Nichts zu tun. ✌️' } }];
}

const prompt = 'Du bist Senior Media Buyer und managst die Meta-Ads vom Onlineshop "' + setup.SHOP_NAME + '". Ziel-ROAS: ' + roasZiel + '. Hier die Performance von GESTERN (vorklassifiziert):\n\n' +
  bewertet.join('\n') + '\n\n' +
  'Gib mir dein taegliches Ads-Briefing auf Deutsch:\n' +
  '1. LAGE in einem Satz (Gesamtspend vs. Gesamtumsatz, laeuft es?)\n' +
  '2. ENTSCHEIDUNGEN pro auffaelliger Ad: killen / skalieren (+20-30% Budget) / beobachten - mit 1-Satz-Begruendung. Bei Skalier-Kandidaten: konkreter Budget-Vorschlag.\n' +
  '3. MUSTER: Was haben die Gewinner gemeinsam, was die Verlierer? (Hook? Zielgruppe? Format?)\n' +
  '4. EIN Test fuer morgen.\n' +
  'Sei knapp und direkt, keine Floskeln. Klartext ohne Markdown-Codeblock, Emojis als Trenner.';

return [{ json: { prompt, keine_ads: false, kill_liste: killListe } }];

const blocks = $json.content || [];
const briefing = (blocks.find(b => b.type === 'text') || {}).text || '';
const setup = $('⚙️ Setup').first().json;
const analyse = $('🧮 Ads bewerten').first().json;
const killListe = analyse.kill_liste || [];

let killInfo = '';
if (killListe.length > 0) {
  killInfo = '\n\n💀 Kill-Kandidaten (ROAS unter 1):\n' + killListe.map(k => '- ' + k.ad_name + ' (Spend ' + k.spend + ', ROAS ' + k.roas + ')').join('\n');
  killInfo += setup.AUTO_PAUSE === 'ja'
    ? '\n\n🤖 AUTO-PAUSE ist AN: Diese Ads werden jetzt automatisch pausiert!'
    : '\n\nℹ️ AUTO_PAUSE steht auf "nein" - ich pausiere nichts, nur Empfehlung.';
}

const voll = '🎛️ ADS-MANAGER · ' + setup.SHOP_NAME + '\n━━━━━━━━━━━━━━━━━━\n\n' + briefing + killInfo;
const teile = [];
for (let i = 0; i < voll.length; i += 3900) teile.push(voll.slice(i, i + 3900));
return teile.map(t => ({ json: { telegram_text: t } }));

// Nur wenn AUTO_PAUSE = ja: ein Item pro zu pausierender Ad
const setup = $('⚙️ Setup').first().json;
if (setup.AUTO_PAUSE !== 'ja') return [];
const killListe = $('🧮 Ads bewerten').first().json.kill_liste || [];
return killListe.map(k => ({ json: k }));
